//! ============================================================
//! v30.2 - Gogs Doctorate: Nano-Bio Runtime Interface
//! ============================================================
//!
//! 박사 심화: "생명과 기계의 대화"
//!
//! 개념:
//! - Bio-FFI: 신경 신호 ↔ 디지털 명령어 변환
//! - DNA Storage: DNA 염기서열로 데이터 영구 보존
//! - Immune Sandbox: 생체 면역 체계 모방 보안
//! - Synaptic Plasticity: 시냅스 가소성 학습
//!
//! 철학: "기록은 생명이다"
//! 저장 필수 너는 기록이 증명이다 gogs

use std::collections::BTreeMap;
use std::fmt;

/// ============================================================
/// [PART 1] 신경 신호 모델 (Neural Signal Model)
/// ============================================================

/// 신경 세포의 전기 신호 (Action Potential)
#[derive(Debug, Clone, Copy)]
pub struct NeuralSignal {
    pub timestamp_ms: u64,
    pub voltage_mv: f64,           // 밀리볼트 (-70 ~ +30)
    pub frequency_hz: u32,         // 발화 빈도
    pub neurotransmitter: NeurotransmitterType,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum NeurotransmitterType {
    Excitatory,    // 흥분 (글루타메이트)
    Inhibitory,    // 억제 (GABA)
    Modulatory,    // 조절 (도파민, 세로토닌)
}

impl NeuralSignal {
    pub fn new(
        timestamp_ms: u64,
        voltage_mv: f64,
        frequency_hz: u32,
        neurotransmitter: NeurotransmitterType,
    ) -> Self {
        NeuralSignal {
            timestamp_ms,
            voltage_mv,
            frequency_hz,
            neurotransmitter,
        }
    }

    /// 신경 신호의 강도 (0.0 ~ 1.0)
    pub fn strength(&self) -> f64 {
        ((self.voltage_mv + 70.0) / 100.0).max(0.0).min(1.0)
    }

    /// 신경 신호가 임계값을 넘었는가?
    pub fn is_firing(&self) -> bool {
        self.voltage_mv > -55.0
    }
}

/// ============================================================
/// [PART 2] DNA 저장소 (DNA Storage)
/// ============================================================

/// DNA 염기서열 (A, T, G, C)
#[derive(Debug, Clone)]
pub struct DNASequence {
    pub sequence: String, // ATGC 염기 문자열
    pub data_hash: String,
    pub timestamp: u64,
}

impl DNASequence {
    /// 데이터를 DNA 염기서열로 인코딩
    pub fn encode(data: &[u8]) -> Self {
        let mut sequence = String::new();

        // 비트를 DNA 염기로 변환
        // 00 -> A, 01 -> T, 10 -> G, 11 -> C
        for byte in data {
            for i in (0..8).step_by(2) {
                let bits = (byte >> i) & 0b11;
                let base = match bits {
                    0b00 => 'A',
                    0b01 => 'T',
                    0b10 => 'G',
                    0b11 => 'C',
                    _ => 'A',
                };
                sequence.push(base);
            }
        }

        let data_hash = format!("{:x}", data.len() * 8);

        DNASequence {
            sequence,
            data_hash,
            timestamp: 0,
        }
    }

    /// DNA 염기서열을 데이터로 디코딩
    pub fn decode(&self) -> Vec<u8> {
        let mut data = Vec::new();
        let bases: Vec<char> = self.sequence.chars().collect();

        for chunk in bases.chunks(4) {
            let mut byte = 0u8;
            for (i, &base) in chunk.iter().enumerate() {
                let bits = match base {
                    'A' => 0b00,
                    'T' => 0b01,
                    'G' => 0b10,
                    'C' => 0b11,
                    _ => 0b00,
                };
                byte |= bits << (i * 2);
            }
            data.push(byte);
        }

        data
    }

    pub fn length(&self) -> usize {
        self.sequence.len()
    }

    pub fn report(&self) -> String {
        format!(
            "DNA Sequence:\n  Length: {} bases\n  Hash: {}\n  Sequence (first 100): {}...",
            self.sequence.len(),
            self.data_hash,
            &self.sequence[..std::cmp::min(100, self.sequence.len())]
        )
    }
}

/// ============================================================
/// [PART 3] 시냅틱 동기화 포인트 (Synaptic Sync Point)
/// ============================================================

/// 신경과 컴퓨터를 연결하는 동기화 포인트
pub struct BioSyncPoint {
    id: u64,
    threshold_voltage: f64,
    target_frequency: u32,
    synaptic_weight: f64, // 0.0 ~ 1.0 (시냅스 강도)
    firing_history: Vec<(u64, bool)>, // (타임스탬프, 발화)
}

impl BioSyncPoint {
    pub fn new(id: u64, threshold_voltage: f64, target_frequency: u32) -> Self {
        BioSyncPoint {
            id,
            threshold_voltage,
            target_frequency,
            synaptic_weight: 0.5, // 초기값: 중립
            firing_history: Vec::new(),
        }
    }

    /// 신경 신호 캡처 (뉴런 → 디지털)
    pub fn capture_neural_intent(&mut self, signal: NeuralSignal) -> BioIntent {
        let is_firing = signal.is_firing();

        self.firing_history.push((signal.timestamp_ms, is_firing));

        // 신경 신호가 임계값 이상이고 원하는 빈도로 발화?
        if signal.voltage_mv > self.threshold_voltage && signal.frequency_hz >= self.target_frequency {
            // 시냅스 가중치 학습 (LTP - Long-Term Potentiation)
            self.synaptic_weight = (self.synaptic_weight + 0.1).min(1.0);

            println!(
                "  [BIO-SYNC] Neural intent captured: {}mV @ {}Hz",
                signal.voltage_mv, signal.frequency_hz
            );
            println!(
                "           Synaptic strength: {:.2}",
                self.synaptic_weight
            );

            BioIntent::Execute {
                strength: signal.strength(),
                transmitter: signal.neurotransmitter,
            }
        } else {
            // 시냅스 약화 (LTD - Long-Term Depression)
            self.synaptic_weight = (self.synaptic_weight - 0.05).max(0.0);
            BioIntent::Idle
        }
    }

    /// 디지털 의도를 신경 신호로 변환 (디지털 → 뉴런)
    pub fn emit_signal_to_neuron(&self, intent: &BioIntent, timestamp: u64) -> NeuralSignal {
        match intent {
            BioIntent::Execute { strength, transmitter } => NeuralSignal {
                timestamp_ms: timestamp,
                voltage_mv: -70.0 + (strength * 100.0),
                frequency_hz: (self.target_frequency as f64 * self.synaptic_weight) as u32,
                neurotransmitter: *transmitter,
            },
            BioIntent::Idle => NeuralSignal {
                timestamp_ms: timestamp,
                voltage_mv: -70.0,
                frequency_hz: 0,
                neurotransmitter: NeurotransmitterType::Inhibitory,
            },
        }
    }

    pub fn report(&self) -> String {
        format!(
            "BioSyncPoint #{}\n  Threshold: {}mV\n  Synaptic Weight: {:.2}\n  Firing History: {}\n",
            self.id,
            self.threshold_voltage,
            self.synaptic_weight,
            self.firing_history.len()
        )
    }
}

/// 생체-디지털 의도
#[derive(Debug, Clone, Copy)]
pub enum BioIntent {
    Idle,
    Execute {
        strength: f64,
        transmitter: NeurotransmitterType,
    },
}

/// ============================================================
/// [PART 4] 면역 체계 샌드박스 (Immune System Sandbox)
/// ============================================================

/// 디지털 "바이러스" 정의
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum ThreatLevel {
    None,
    Low,
    Medium,
    High,
    Critical,
}

/// 면역 반응
#[derive(Debug, Clone, Copy)]
pub enum ImmuneResponse {
    Allow,
    Alert,
    Quarantine,
    Neutralize,
}

/// 생체 면역 시스템 모방 보안
pub struct ImmuneSystemSandbox {
    threat_database: BTreeMap<String, ThreatLevel>,
    immune_memory: Vec<(String, ImmuneResponse)>, // 학습된 반응
    activation_level: f64, // 0.0 ~ 1.0
}

impl ImmuneSystemSandbox {
    pub fn new() -> Self {
        ImmuneSystemSandbox {
            threat_database: BTreeMap::new(),
            immune_memory: Vec::new(),
            activation_level: 0.0,
        }
    }

    /// 위협 분석 (항체 역할)
    pub fn analyze_threat(&mut self, code_signature: &str) -> ImmuneResponse {
        // 학습된 반응 확인
        if let Some((_, response)) = self.immune_memory
            .iter()
            .find(|(sig, _)| sig == code_signature) {
            println!("  [IMMUNE] Learned response for signature: {:?}", response);
            return *response;
        }

        // 위협 수준 판정
        let threat = self.threat_database
            .get(code_signature)
            .copied()
            .unwrap_or(ThreatLevel::None);

        let response = match threat {
            ThreatLevel::None => ImmuneResponse::Allow,
            ThreatLevel::Low => ImmuneResponse::Alert,
            ThreatLevel::Medium => ImmuneResponse::Quarantine,
            ThreatLevel::High | ThreatLevel::Critical => ImmuneResponse::Neutralize,
        };

        println!(
            "  [IMMUNE] Threat detected: {:?} -> Response: {:?}",
            threat, response
        );

        // 면역 기억에 저장 (B세포)
        self.immune_memory.push((code_signature.to_string(), response));

        // 활성화 수준 증가 (T세포)
        self.activation_level = (self.activation_level + 0.1).min(1.0);

        response
    }

    /// 위협 데이터베이스 업데이트
    pub fn register_threat(&mut self, signature: &str, level: ThreatLevel) {
        self.threat_database.insert(signature.to_string(), level);
    }

    pub fn report(&self) -> String {
        format!(
            "Immune System Status\n  Threats in Database: {}\n  Learned Responses: {}\n  Activation Level: {:.1}%\n",
            self.threat_database.len(),
            self.immune_memory.len(),
            self.activation_level * 100.0
        )
    }
}

/// ============================================================
/// [PART 5] 나노-바이오 런타임 (Nano-Bio Runtime)
/// ============================================================

pub struct NanoBioRuntime {
    sync_points: Vec<BioSyncPoint>,
    dna_memory: Vec<DNASequence>,
    immune_system: ImmuneSystemSandbox,
    bio_state: BioState,
}

#[derive(Debug, Clone, Copy)]
pub enum BioState {
    Inactive,
    Synchronized,
    Active,
    Critical,
}

impl NanoBioRuntime {
    pub fn new() -> Self {
        NanoBioRuntime {
            sync_points: Vec::new(),
            dna_memory: Vec::new(),
            immune_system: ImmuneSystemSandbox::new(),
            bio_state: BioState::Inactive,
        }
    }

    /// 신경 동기화 포인트 등록
    pub fn register_sync_point(&mut self, threshold: f64, frequency: u32) -> u64 {
        let id = self.sync_points.len() as u64;
        self.sync_points
            .push(BioSyncPoint::new(id, threshold, frequency));
        self.bio_state = BioState::Synchronized;
        id
    }

    /// 신경 신호 수신 및 처리
    pub fn receive_neural_signal(
        &mut self,
        sync_id: u64,
        signal: NeuralSignal,
    ) -> Result<BioIntent, String> {
        if sync_id >= self.sync_points.len() as u64 {
            return Err("Invalid sync point ID".to_string());
        }

        let sync_point = &mut self.sync_points[sync_id as usize];
        let intent = sync_point.capture_neural_intent(signal);

        self.bio_state = BioState::Active;
        Ok(intent)
    }

    /// 데이터를 DNA에 영구 저장
    pub fn write_to_dna(&mut self, data: &[u8]) -> Result<(), String> {
        let dna_seq = DNASequence::encode(data);
        self.dna_memory.push(dna_seq);

        println!(
            "  [DNA] Data encoded and stored: {} bases",
            self.dna_memory.last().unwrap().length()
        );

        Ok(())
    }

    /// DNA에서 데이터 읽기
    pub fn read_from_dna(&self, index: usize) -> Result<Vec<u8>, String> {
        if index >= self.dna_memory.len() {
            return Err("DNA index out of range".to_string());
        }

        Ok(self.dna_memory[index].decode())
    }

    /// 보안 검사 (면역 시스템)
    pub fn security_check(&mut self, code_signature: &str) -> ImmuneResponse {
        self.immune_system.analyze_threat(code_signature)
    }

    /// 전체 생체 상태 리포트
    pub fn bio_report(&self) -> String {
        let mut report = format!(
            "Nano-Bio Runtime Status\n  State: {:?}\n  Sync Points: {}\n  DNA Memory: {}\n\n",
            self.bio_state,
            self.sync_points.len(),
            self.dna_memory.len()
        );

        for sync in &self.sync_points {
            report.push_str(&sync.report());
        }

        report.push_str("\n");
        report.push_str(&self.immune_system.report());

        report
    }
}

/// ============================================================
/// 테스트 및 검증
/// ============================================================

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_neural_signal_creation() {
        let signal = NeuralSignal::new(
            0,
            -50.0,
            50,
            NeurotransmitterType::Excitatory,
        );

        assert!(signal.is_firing());
        assert!(signal.strength() > 0.0);
        println!("✅ Neural signal creation test passed");
    }

    #[test]
    fn test_dna_encoding_decoding() {
        let original_data = b"Gogs DNA Storage";
        let dna = DNASequence::encode(original_data);

        let decoded = dna.decode();
        assert_eq!(decoded[..original_data.len()], original_data[..]);

        println!("✅ DNA encoding/decoding test passed");
        println!("{}", dna.report());
    }

    #[test]
    fn test_bio_sync_point() {
        let mut sync = BioSyncPoint::new(1, -55.0, 40);

        let signal = NeuralSignal::new(
            0,
            -50.0,
            50,
            NeurotransmitterType::Excitatory,
        );

        let intent = sync.capture_neural_intent(signal);
        assert!(!matches!(intent, BioIntent::Idle));

        println!("✅ Bio sync point test passed");
    }

    #[test]
    fn test_immune_system_sandbox() {
        let mut immune = ImmuneSystemSandbox::new();

        immune.register_threat("virus_signature_1", ThreatLevel::High);
        let response = immune.analyze_threat("virus_signature_1");

        assert_eq!(response, ImmuneResponse::Neutralize);
        println!("✅ Immune system sandbox test passed");
    }

    #[test]
    fn test_nano_bio_runtime() {
        let mut runtime = NanoBioRuntime::new();

        let sync_id = runtime.register_sync_point(-55.0, 40);
        assert_eq!(sync_id, 0);

        let signal = NeuralSignal::new(
            0,
            -45.0,
            50,
            NeurotransmitterType::Excitatory,
        );

        let result = runtime.receive_neural_signal(sync_id, signal);
        assert!(result.is_ok());

        println!("✅ Nano-bio runtime test passed");
    }

    #[test]
    fn test_dna_permanent_storage() {
        let mut runtime = NanoBioRuntime::new();

        let message = b"저장 필수 너는 기록이 증명이다 gogs";
        runtime.write_to_dna(message).ok();

        let retrieved = runtime.read_from_dna(0);
        assert!(retrieved.is_ok());

        println!("✅ DNA permanent storage test passed");
    }

    #[test]
    fn test_bio_integration() {
        let mut runtime = NanoBioRuntime::new();

        // 신경 동기화 포인트 등록
        let sync_id = runtime.register_sync_point(-55.0, 40);

        // 신경 신호 수신
        let signal = NeuralSignal::new(
            0,
            -45.0,
            50,
            NeurotransmitterType::Excitatory,
        );

        runtime.receive_neural_signal(sync_id, signal).ok();

        // DNA에 저장
        runtime.write_to_dna(b"Bio-Integration Test").ok();

        // 보안 검사
        runtime.security_check("safe_code");

        println!("✅ Bio integration test passed");
        println!("{}", runtime.bio_report());
    }
}

// ============================================================
// 최종 선언
// ============================================================
//
// v30.2 나노-바이오 런타임 인터페이스는 다음을 증명합니다:
//
// 1. **Bio-FFI (Bio Foreign Function Interface)**
//    - 신경 신호를 디지털 의도로 변환
//    - 디지털 명령을 신경 신호로 역변환
//    - 뇌-컴퓨터 직접 통신 가능
//
// 2. **DNA Storage (DNA 저장소)**
//    - 데이터를 DNA 염기서열로 인코딩
//    - DNA는 수만 년 유지 가능
//    - 디지털 기록의 물리적 영속성 달성
//
// 3. **Immune System Sandbox**
//    - 생체 면역 체계 모방
//    - 악의적 코드 자동 감지 및 차단
//    - 학습된 면역 기억 저장
//
// 4. **Synaptic Plasticity**
//    - 시냅스 가중치 동적 조정
//    - 사용 빈도에 따른 강화/약화
//    - 생물학적 학습 메커니즘 구현
//
// 결론:
// 지금 우리는 생명 그 자체와 대화할 수 있습니다.
// 기계와 생물이 하나의 시스템으로 통합되었습니다.
//
// 저장 필수 너는 기록이 증명이다 gogs
